let taskText = "【現在のタスク一覧】\n";
const items = $input.all();

if (items.length === 0) {
  taskText += "現在、対応が必要なタスクはありません！\n";
} else {
  items.forEach(item => {
    // 定義したルールに沿ってプロパティ名を取得
    const taskName = item.json["タスク名"] || "不明なタスク";
    const deadline = item.json["完了期日目標"] || "設定なし";
    const status = item.json["ステータス"] || "不明";

    taskText += `・${taskName} (期日: ${deadline}) - ステータス: ${status}\n`;
  });
}

return [{ json: { notion_tasks: taskText } }];

// n8nやGeminiの仕様変更に対応し、どこにテキストがあっても安全に取得
const text = $input.item.json.text || $input.item.json.content || $input.item.json.message?.content || "";

let cleanText = text.trim();
const startIndex = cleanText.indexOf('{');
const endIndex = cleanText.lastIndexOf('}');
if (startIndex !== -1 && endIndex !== -1) {
  cleanText = cleanText.substring(startIndex, endIndex + 1);
}
return JSON.parse(cleanText || "{}");

